define("text!templates/app/applayout.html", function () { return "<script type=\"text/template\" id=\"applayout-template\">\n\n    <div id=\"content-container\" class=\"container\"> </div>\n\n    <div id=\"menu-container\" class=\"container\"> </div>\n\n    <div id=\"nav-container\" class=\"container\"></div>\n\n    <div id=\"intro-container\" class=\"container\"></div>\n\n    <div id=\"help-container\" class=\"container\"> </div>\n\n    <div id=\"resources-container\" class=\"container\"></div>\n\n    <div id=\"loading-container\" class=\"container\"> </div>\n\n    <div id=\"ta-container\" class=\"container\"> </div>\n\n    <div id=\"debug-container\" class=\"container\"></div>\n\n    <div id=\"winfocus-container\" class=\"container\"> </div>\n</script>\n"; });
define("text!templates/app/bookends/introview.html", function () { return "<script type=\"text/template\" id=\"introview-template\">\n\n    <div id=\"intro-view\" >\n        <img class=\"bg-image\" src=\"assets/images/intro/intro-bg.jpg\"/>\n\n\n        <img class=\"intro-pandora-logo\" src=\"assets/images/intro/intro-pandora-logo.png\"/>\n        <img class=\"intro-rote-logo\" src=\"assets/images/intro/intro-rote-logo.png\"/>\n\n        <div class=\"intro-academy-group\">\n            <img class=\"intro-academy-logo\" src=\"assets/images/intro/intro-academy-logo.png\"/>\n            <img class=\"intro-academy-text\" src=\"assets/images/intro/intro-academy-text.png\"/>\n        </div>\n\n        <div class=\"intro-banner-container\">\n            <img class=\"intro-banner\" src=\"assets/images/intro/intro-banner.png\"/>\n        </div>\n\n        <div class=\"intro-maximize-window\">For the best experience,<br>maximize your browser window!</div>\n\n        <div id=\"intro-rolechooser-container\">\n\n            <div class=\"input-item\">\n                <select id=\"intro-user-role\" class=\"styled-select\" name=\"foo\">\n                    <option value=\"\" disabled selected>Select your role</option>\n                    <% _.each(roleChooser.roles, function(role){ %>\n                    <option value=\"<%= _.escape(role.id)%>\">\n                        <%= _.escape(role.title) %>\n                    </option>\n                    <% }); %>\n                </select>\n                <div id=\"intro-continue-button\" data-id=\"continue\"></div>\n            </div>\n        </div>\n\n\n    </div>\n\n</script>"; });
define("text!templates/app/debug/debugview.html", function () { return "<script type=\"text/template\" id=\"debugview-template\">\n\n    <div id=\"debug-view\">\n        <div id=\"debug-scrim\" class=\"scrim-background\"></div>\n\n        <div class=\"popup-view debug-popup\">\n            <div class=\"content\">\n                <h1 class=\"popup-title\">Debugger</h1>\n                <p class=\"debug-version\">(<%= version %>)</p>\n                <div class=\"debug-label-row\">\n                    <div class=\"debug-fold-arrow\" data-id=\"row-change-role\"></div>\n                    <p class=\"debug-label\" >Change role:</p>\n                </div>\n\n                <div class=\"debug-row\" id=\"row-change-role\">\n                    <select id=\"debug-user-role\" class=\"styled-select\" name=\"foo\">\n                        <% _.each(roleChooser.roles, function(role){ %>\n                        <option value=\"<%= _.escape(role.id)%>\">\n                            <%= _.escape(role.title) %>\n                        </option>\n                        <% }); %>\n                    </select>\n                    <a class=\"debug-link\" id=\"debug-change-role\" data-id=\"apply-role\" href=\"#\">Apply</a>\n                    <a class=\"debug-link\" id=\"debug-cancel-role\" data-id=\"cancel-role\" href=\"#\">Revert</a>\n                </div>\n                <hr />\n\n                <div class=\"debug-label-row\">\n                    <div class=\"debug-fold-arrow\" data-id=\"row-mark-individual\"></div>\n                    <p class=\"debug-label\" >Change submodules individually:</p>\n                </div>\n                <div class=\"debug-row\" id=\"row-mark-individual\">\n                    <input type=\"text\" id=\"debug-status\">\n                    <a class=\"debug-link\" id=\"debug-submit\" data-id=\"apply-status\" href=\"#\">Apply</a>\n                    <a class=\"debug-link\" id=\"debug-revert\" data-id=\"cancel-status\" href=\"#\">Revert</a>\n                </div>\n\n                <hr />\n\n                <div class=\"debug-label-row\">\n                    <div class=\"debug-fold-arrow\" data-id=\"row-mark-all\"></div>\n                    <p class=\"debug-label\" >Change submodules globally:</p>\n                </div>\n                <div class=\"debug-row\" id=\"row-mark-all\">\n                    <a class=\"debug-link\" id=\"debug-notstarted\" data-id=\"notstarted\" href=\"#\">Not Started</a>\n                    <a class=\"debug-link\" id=\"debug-started\" data-id=\"started\" href=\"#\">Started</a>\n                    <a class=\"debug-link\" id=\"debug-completed\" data-id=\"completed\" href=\"#\">Completed</a>\n                    <a class=\"debug-link\" id=\"debug-initial\" data-id=\"initial\" href=\"#\">1|0...</a>\n                    <a class=\"debug-link\" id=\"debug-last\" data-id=\"last\" href=\"#\">...2|0</a>\n\n                    <a class=\"debug-link\" id=\"debug-unlock\" data-id=\"unlock\" href=\"#\">Unlock All</a>\n\n                </div>\n                <hr />\n\n                <div class=\"debug-label-row\">\n                    <div class=\"debug-fold-arrow\" data-id=\"row-change-question\"></div>\n                    <p class=\"debug-label\" >Submodule functionality:</p>\n                </div>\n                <div class=\"debug-row\" id=\"row-change-question\">\n                    <a class=\"debug-link\" id=\"debug-skip-splash\" data-id=\"skip-splash\" href=\"#\">Skip Splash</a>\n                    <a class=\"debug-link\" id=\"debug-show-conclusion\" data-id=\"show-conclusion\" href=\"#\">Show Conclusion</a>\n                    <a class=\"debug-link\" id=\"debug-next-ques\" data-id=\"next-ques\" href=\"#\">Next Q ></a>\n                    <a class=\"debug-link\" id=\"debug-prev-ques\" data-id=\"prev-ques\" href=\"#\">< Prev Q</a>\n                </div>\n                <hr />\n\n                <div class=\"debug-label-row\">\n                    <div class=\"debug-fold-arrow\" data-id=\"row-reset-values\"></div>\n                    <p class=\"debug-label\" >Reset stored values:</p>\n                </div>\n                <p>NB - This will clear all stored values and require a browser refresh.</p>\n                <div class=\"debug-row\" id=\"row-reset-values\">\n                    <a class=\"debug-link\" id=\"debug-clear-storage\" data-id=\"clear-storage\" href=\"#\">Clear Stored Values</a>\n                </div>\n                <div id=\"row-toggle-all\">\n                    <a id=\"debug-toggle-all\" href=\"#\">Show all</a>\n                </div>\n\n\n            </div>\n\n\n            <div data-id=\"close\" class=\"close-x-button\"></div>\n\n        </div>\n\n    </div>\n\n</script>"; });
define("text!templates/app/loadingpage.html", function () { return "<script type=\"text/template\" id=\"loadingpage-template\">\n    <div id=\"loading-view\">\n        <div class=\"bg-texture\"></div>\n        <div class=\"loader-holder\">\n            <div class=\"loader-bg\">\n\n            </div>\n            <div class=\"loader-mask\">\n                <div class=\"loader-P\"></div>\n            </div>\n            <div class=\"loader-msg\">0%</div>\n        </div>\n    </div>\n\n\n</script>"; });
define("text!templates/app/menu/menuview-dev.html", function () { return "<script type=\"text/template\" id=\"menuview-dev-template\">\n    <div id=\"menu-view\">\n        <div id=\"menu-content\">\n            <div class=\"bg-texture\"></div>\n            <img id=\"menu-dev-bg\" src=\"assets/images/menu/menu-mock.jpg\"/>\n\n\n\n            <% _.each(app.model.get('menu'), function(item, index) { %>\n            <div id=\"menu-dev-container<%= index %>\" class=\"menu-dev-container\">\n                <h1 class=\"module-name\">JAZZ  <span class=\"module-number\"><%= item.id  %></span>: <%= item.name  %></h1>\n                <% _.each(item.modules, function(module) { %>\n                    <% var statusClass = module.status == 0 ? 'not-started' : module.status == 1 ? 'started' : 'completed';  %>\n                    <div id=\"menu-button-<%= module.moduleName %>\" data-id=\"<%= module.moduleName %>\" class=\"menu-button <%= statusClass %>\"><div class=\"status-icon\"></div><h3 class=\"menu-button-label\"><%= module.title %></h3></div>\n                <%  }); %>\n            </div>\n            <%  }); %>\n\n            <div class=\"menu-card-popup\" style=\"position: absolute; left: 50%; top: 100px\">\n                <div class=\"content\">\n                    <h1>This is the title.</h1>\n                    <p>Drumstick cow meatloaf sausage strip steak ham hock short ribs shankle flank jerky bresaola pork chop pork. Prosciutto jowl doner picanha brisket leberkas frankfurter kevin capicola rump shoulder ground round pancetta pastrami. Pork loin porchetta tail pork belly spare ribs rump turducken shoulder shankle short loin turkey chuck bacon</p>\n                </div>\n            </div>\n\n        </div>\n    </div>\n\n</script>"; });
define("text!templates/app/nav/navview.html", function () { return "<script type=\"text/template\" id=\"navview-template\">\n\n    <div id=\"nav-view\">\n        <div class=\"nav-info-container\"></div>\n\n\n\n        <div class=\"nav-slideout-container\">\n\n\n            <div class=\"badge-container slideout-view\">\n                <div class=\"overlay-texture\"></div>\n\n            </div>\n\n            <div class=\"progress-container slideout-view\">\n                <div class=\"overlay-texture\"></div>\n            </div>\n\n            <div class=\"resources-container slideout-view\">\n                <div class=\"overlay-texture\"></div>\n\n            </div>\n\n            <div class=\"sound-container slideout-view\">\n                <div class=\"overlay-texture\"></div>\n            </div>\n\n        </div>\n        <div class=\"nav-button-container\">\n            <% _.each(buttons, function(button, index) { %>\n            <div data-id=\"<%=button.id%>\" data-tooltip=\"<%=button.label%>\" class=\"<%=button.id%>-ibutton nav-button enabled\"></div>\n            <% }); %>\n            <div class=\"nav-button info-ibutton enabled\" data-id=\"info\" data-tooltip=\"Directions\"></div>\n        </div>\n        <div class=\"nav-tooltip\"><p></p></div>\n\n    </div>\n\n\n</script>"; });
define("text!templates/app/nav/overlays/badgeview.html", function () { return "<script type=\"text/template\" id=\"badgeview-template\">\n\n\n    <div id=\"badge-view\">\n        <div class=\"overlay-title\"><div class=\"badge-ititle title-icon\"></div>Badges</div>\n        <div class=\"badge-box\">\n        <% _.each(badges, function (module, index) { %>\n            <div class=\"badge-holder\" id=\"<%= module.get('badge').id %>\" >\n                <div class=\"badge-ghost\"><div class=\"badge-banner\"></div></div>\n                <img class=\"badge\" src=\"assets/images/badges/<%= module.get('badge').id %>.png\" />\n\n                <div class=\"badge-banner\"><h1><%= module.get('badge').name %></h1></div>\n            </div>\n        <% }); %>\n        </div>\n    </div>\n    <div class=\"close-ibutton enabled\" data-id=\"close\"></div>\n\n</script>"; });
define("text!templates/app/nav/overlays/helpview.html", function () { return "<script type=\"text/template\" id=\"help-view-template\">\n\n    <div class=\"popup-view help-popup\">\n        <div class=\"content\">\n            <h1 class=\"popup-title\"></h1>\n            <div class=\"popup-body\"></div>\n        </div>\n\n        <hr />\n        <div class=\"help-links\">\n            <div class=\"role-display\">\n                <p id=\"selected-role-label\">Selected Role: </p>\n                <p id=\"selected-role\"></p>\n            </div>\n            <a class=\"help-link\" id=\"help-role\" data-id=\"role\" href=\"#\">Change role</a>\n            <div class=\"link-separator\"></div>\n            <a class=\"help-link\" id=\"help-jira\" data-id=\"jira\" href=\"#\">Report a bug</a>\n        </div>\n\n    </div>\n    <div class=\"popup-view role-selection-popup\">\n        <div class=\"content\">\n            <h1 class=\"popup-title\">Role</h1>\n            <div class=\"popup-body\"><p>Select your role, then click Submit.</p></div>\n        </div>\n\n        <div class=\"help-role-selector\">\n\n            <select id=\"help-user-role\" class=\"styled-select\" name=\"foo\">\n                <% _.each(roleChooser.roles, function(role){ %>\n                <option value=\"<%= _.escape(role.id)%>\">\n                    <%= _.escape(role.title) %>\n                </option>\n                <% }); %>\n            </select>\n            <button class=\"role-selection-button\" data-id=\"cancel\">Cancel</button>\n            <button class=\"role-selection-button\" data-id=\"submit\">Submit</button>\n        </div>\n\n        <div data-id=\"close-selection\" class=\"close-x-button\"></div>\n\n\n    </div>\n\n\n</script>"; });
define("text!templates/app/nav/overlays/progressview.html", function () { return "<script type=\"text/template\" id=\"progress-template\">\n\n\n    <div id=\"progress-view\">\n        <div class=\"overlay-title\">Overall Progress</div>\n        <div class=\"progress-text\"></div>\n        <div class=\"progress-text-completed\">COMPLETED</div>\n    </div>\n\n</script>"; });
define("text!templates/app/nav/overlays/resourceview.html", function () { return "<script type=\"text/template\" id=\"resourceview-template\">\n\n\n    <div id=\"resources-view\">\n        <div class=\"overlay-title\"><div class=\"resources-ititle title-icon\"></div>Resources</div>\n        <div class=\"resource-container\">\n            <div class=\"resource-list\">\n                <%  _.each(filteredGroups, function (group) { %>\n                <div class=\"resource-group\">\n                <h1><%= group.label %></h1>\n\n                    <%  _.each(group.links, function (link) { %>\n                    <p><a target=\"_blank\" href=\"<%= link.url %>\"><%= link.text %></a></p>\n                    <%  }); %>\n\n                </div>\n                <%  }); %>\n            </div>\n        </div>\n    </div>\n    <div class=\"close-ibutton enabled\" data-id=\"close\"></div>\n\n</script>"; });
define("text!templates/app/nav/overlays/soundview.html", function () { return "<script type=\"text/template\" id=\"soundview-template\">\n\n\n    <div id=\"sound-view\">\n        <div class=\"sound-text\"></div>\n    </div>\n\n</script>"; });
define("text!templates/app/ta/taview.html", function () { return "<script type=\"text/template\" id=\"taview-template\">\n\n    <div id=\"ta-view\">\n        <div id=\"winfocus-scrim\" class=\"scrim-background\"></div>\n\n        <div class=\"popup-view ta-popup\">\n            <div class=\"content\">\n                <h1 class=\"popup-title\"><%= text.header %></h1>\n                <div class=\"popup-body\">\n                    <p><%= text.body %></p>\n                    <div class=\"ta-guides\">\n                        <%  _.each(groups, function (group) { %>\n                        <p class=\"ta-group\"><b><%= group.label %></b></p>\n                        <ul>\n                            <%  _.each(group.links, function (link) { %>\n                            <li><a target=\"_blank\" href=\"<%= link.url %>\"><%= link.text %></a></li>\n                            <%  }); %>\n                        </ul>\n                        <%  }); %>\n                    </div>\n                </div>\n\n\n            </div>\n\n            <hr />\n            <div class=\"ta-links\">\n\n                <a class=\"ta-link\" id=\"ta-unlock\" data-id=\"unlock\" href=\"#\">Unlock all modules</a>\n\n            </div>\n\n            <div data-id=\"close\" class=\"close-x-button\"></div>\n\n        </div>\n\n    </div>\n\n</script>"; });
define("text!templates/app/winfocus/winfocus.html", function () { return "<script type=\"text/template\" id=\"winfocus-template\">\n    <div class=\"winfocus-view\">\n        <div id=\"winfocus-scrim\" class=\"scrim-background\"></div>\n        <div id=\"winfocus-resume-button\">Resume</div>\n    </div>\n\n</script>"; });
define("text!templates/interactions/click_reveal/cr-044-mainview.html", function () { return "<script type=\"text/template\" id=\"cr44-mainview-template\">\n\n\n    <div id=\"cr-44-view\" >\n        <div class=\"bg-img\"></div>\n\n        <div><h1 class=\"module-title\"><%= name %></h1></div>\n\n\n        <div class=\"cr-44-container\">\n\n\n            <%  _.each(items, function (item, index) { %>\n                <div class=\"coaster cr-item\" data-id=\"<%= item.id %>\">\n                    <div class=\"coaster-label\">\n                        <div class=\"coaster-done-check\"></div>\n                        <h1><%= (index + 1) %></h1>\n                        <h2>STEP</h2>\n                    </div>\n                </div>\n            <% }); %>\n\n        </div>\n\n        <div class=\"scrim-background\"></div>\n\n        <div class=\"feedback-container\"></div>\n\n        <div class=\"continue-button main-button enabled\" data-id=\"continue\">Continue</div>\n\n\n        <div class=\"splash-container\"></div>\n        <div class=\"conclusion-container\"></div>\n\n    </div>\n\n</script>"; });
define("text!templates/interactions/click_reveal/cr-058-mainview.html", function () { return "<script type=\"text/template\" id=\"cr58-mainview-template\">\n\n\n    <div id=\"cr-58-view\" >\n        <div class=\"bg-img\"></div>\n\n        <div><h1 class=\"module-title\"><%= name %></h1></div>\n\n\n        <div class=\"cr-58-container\">\n\n\n            <%  _.each(items, function (item, index) { %>\n                <div class=\"napkin cr-item\" data-id=\"<%= item.id %>\">\n                    <div class=\"doodle\"></div>\n                    <div class=\"napkin-done-check\"></div>\n                    <h1 class=\"napkin-label\"><%= item.header %></h1>\n                </div>\n            <% }); %>\n\n        </div>\n\n        <div class=\"scrim-background\"></div>\n\n        <div class=\"feedback-container\"></div>\n\n        <div class=\"continue-button main-button enabled\" data-id=\"continue\">Continue</div>\n\n\n        <div class=\"splash-container\"></div>\n        <div class=\"conclusion-container\"></div>\n\n    </div>\n\n</script>"; });
define("text!templates/interactions/dnd_matching/matching-049-mainview.html", function () { return "<script type=\"text/template\" id=\"mainview-template\">\n\n    <div id=\"match-049-view\" style=\"background-color: <%=bg_info.backgroundColor%>;\">\n        <div class=\"<%=bg_info.backgroundClass%>\"></div>\n\n        <div><h1 class=\"module-title\"><%= name %></h1></div>\n\n        <div class=\"match-049-targets target-container\">\n            <% _.each(items, function (item, index) { %>\n            <div class=\"match-049-target drag-target\" data-id=\"<%= item.id %>\">\n                <div class=\"content\">\n                    <h1 class=\"match-049-label\">-- ? --</h1>\n                    <p class=\"match-049-description\"><%= item.description %></p>\n                </div>\n                <div class=\"match-049-undo-button undo-button\">UNDO DRAG</div>\n            </div>\n            <% }); %>\n        </div>\n\n        <div class=\"match-049-items drag-container\">\n            <% if(randomize) { items = _.shuffle(items); } %>\n            <% _.each(items, function (item, index) { %>\n            <div class=\"match-049-item drag-item\" data-id=\"<%= item.id %>\">\n                <h1 class=\"match-049-label\"><%= item.title %></h1>\n            </div>\n            <% }); %>\n        </div>\n\n\n\n        <div class=\"main-button submit-button\">Check Answers</div>\n\n        <div class=\"scrim-background\"></div>\n\n        <div class=\"popup-container\"></div>\n\n        <div class=\"splash-container\"></div>\n        <div class=\"conclusion-container\"></div>\n\n\n    </div>\n\n\n</script>"; });
define("text!templates/interactions/dnd_matching/matching-050-mainview.html", function () { return "<script type=\"text/template\" id=\"mainview-template\">\n\n    <div id=\"match-050-view\" style=\"background-color: <%=bg_info.backgroundColor%>;\">\n        <div class=\"<%=bg_info.backgroundClass%>\"></div>\n\n        <div><h1 class=\"module-title\"><%= name %></h1></div>\n\n        <div class=\"match-050-targets target-container\">\n            <h1 class=\"match-050-music-title\"><%= text.targetTitle %></h1>\n            <% _.each(items, function (item, index) { %>\n            <div class=\"match-050-target drag-target\" data-id=\"<%= item.id %>\">\n                <div class=\"content\">\n                    <h1 class=\"match-050-label\">-- ? --</h1>\n                    <p class=\"match-050-description\"><%= item.description %></p>\n                </div>\n                <div class=\"match-050-undo-button undo-button\">undo</div>\n            </div>\n            <% }); %>\n            <div class=\"match-050-targets-bg\"></div>\n        </div>\n\n        <div class=\"match-050-items drag-container\">\n            <% if(randomize) { items = _.shuffle(items); } %>\n            <% _.each(items, function (item, index) { %>\n            <div class=\"match-050-item drag-item\" data-id=\"<%= item.id %>\">\n                <div class=\"match-050-item-img\" data-id=\"<%= item.id %>\"></div>\n                <h1 class=\"match-050-label\"><%= item.title %></h1>\n            </div>\n            <% }); %>\n        </div>\n\n\n\n        <div class=\"main-button submit-button\">Check Answers</div>\n\n        <div class=\"scrim-background\"></div>\n\n        <div class=\"popup-container\"></div>\n\n        <div class=\"splash-container\"></div>\n        <div class=\"conclusion-container\"></div>\n\n\n    </div>\n\n\n</script>"; });
define("text!templates/interactions/dnd_pillars/mainview.html", function () { return "<script type=\"text/template\" id=\"audio2-mainview-template\">\n\n    <div id=\"audio2-view\" style=\"background-color:<%= colors.backgroundColor %>;\">\n        <div class=\"bg-texture\"></div>\n\n        <div class=\"module-title color-<%= modulename %>\"><h1 style=\"color:<%= colors.highlightColor %>;\"><%= name %></h1></div>\n\n        <div class=\"audio2-bg-elements\"></div>\n\n        <div class=\"audio2-container\">\n            <div class=\"audio2-question-container\"></div>\n            <div class=\"audio2-ad-slots\">\n\n            </div>\n            <div class=\"audio2-hr\"></div>\n            <div class=\"audio2-ads\">\n                <div class=\"audio2-adcontainer\" id=\"adholder-everywhere\"><div class=\"ad-holder\"></div><div class=\"ad-counter\"></div></div>\n                <div class=\"audio2-adcontainer\" id=\"adholder-platform\"><div class=\"ad-holder\"></div><div class=\"ad-counter\"></div></div>\n            </div>\n        </div>\n\n        <div class=\"main-button submit-button enabled\" data-id=\"submit\">Check Answers</div>\n\n        <div class=\"scrim-background\"></div>\n\n        <div class=\"feedback-container\"></div>\n\n\n        <div class=\"splash-container\"></div>\n        <div class=\"conclusion-container\"></div>\n\n    </div>\n\n</script>"; });
define("text!templates/interactions/dnd_sorting/mainview.html", function () { return "<script type=\"text/template\" id=\"responsibilities1-mainview-template\">\n\n    <div id=\"resp1-view\" style=\"background-color:<%= backgroundColor %>;\">\n        <div class=\"bg-texture-bottom\"></div><div class=\"bg-texture-middle\"></div><div class=\"bg-texture-top\"></div>\n\n        <h1 class=\"module-title\"><%= name %></h1>\n        \n        <div class=\"resp1-line-bg unselectable\"></div>\n        <div class=\"resp1-cases unselectable\">\n            <img class=\"resp1-cases-shadow unselectable\" src=\"assets/images/responsibilities1/cases-shadow.png\" />\n            <% _.each(roles, function (role, index) { %>\n            <div class=\"resp1-case unselectable\" id=\"resp1-cases-<%= role.id %>\" data-id=\"<%= role.id %>\">\n                <div class=\"drag-holder\"></div>\n            </div>\n            <div class=\"resp1-cases-mask unselectable\"></div>\n            <div class=\"resp1-label label-<%= index %>\"><%= role.label %></div>\n            <% }); %>\n        </div>\n\n\n\n        <div class=\"resp1-role-description sketch-box-solid unselectable\">\n            <div class=\"top\"></div><div class=\"right\"></div><div class=\"bottom\"></div><div class=\"left\"></div><div class=\"center\"></div>\n            <div class=\"content\"></div>\n        </div>\n\n        <div class=\"resp1-nOFn unselectable\"></div>\n\n        <div class=\"resp1-role-coin\">\n            <div class=\"resp1-role-coin-shadow\"></div>\n            <div class=\"resp1-role-coin-center\"></div>\n        </div>\n\n\n            <% _.each(roles, function (role, index) { %>\n                <div class=\"resp1-final-feedback\" id=\"resp1-final-feedback<%=index+1%>\">\n                    <div class=\"content\">\n                        <h1><%= role.label %></h1>\n                        <% _.each(role.responsibilities, function (resp, index) { %>\n                            <li><%= resp.text %></li>\n                        <% }); %>\n                    </div>\n                </div>\n            <% }); %>\n\n\n        <div class=\"main-button submit-button\" data-id=\"submit\">Check Answers</div>\n        <div class=\"main-button continue-button enabled\" data-id=\"continue\">Continue</div>\n\n        <div class=\"scrim-background\"></div>\n\n        <div class=\"popup-container\"></div>\n\n        <div class=\"splash-container\"></div>\n        <div class=\"conclusion-container\"></div>\n\n\n    </div>\n\n\n</script>"; });
define("text!templates/interactions/hotspots/mainview.html", function () { return "<script type=\"text/template\" id=\"hotspots-mainview-template\">\n\n    <div id=\"hs-049-view\" style=\"background-color: <%=bg_info.backgroundColor%>;\">\n        <div class=\"bg-img\"></div>\n\n        <div><h1 class=\"module-title\"><%= name %></h1></div>\n\n\n        <div class=\"items-container\">\n\n                <%  _.each(items, function (item, index) { %>\n                <div class=\"item-container item-button>\" data-id=\"<%= item.id  %>\">\n                    <h1><%= item.label %></h1>\n                    <h2><%= item.price %></h2>\n                    <div class=\"item-done-check\"></div>\n                </div>\n\n                <% }); %>\n\n\n        </div>\n\n\n\n        <div class=\"details-container\">\n            <% var index = 0 %>\n            <%  _.each(items, function (item, i) { %>\n                <div class=\"detail-set\" data-id=\"<%= item.id  %>\">\n                    <img class=\"screenshot-bg\" src=\"<%= item.image  %>\" />\n\n                    <%  _.each(item.details, function (detail, j) { %>\n                        <div class=\"detail-info-button detail-button\" data-id=\"<%= j %>\" data-index=\"<%= index %>\" style=\"top: <%= detail.button.y %>px; left: <%= detail.button.x %>px;\">\n                        </div>\n                    <% }); %>\n\n                    <% index++; %>\n                </div>\n\n            <% }); %>\n            <div class=\"tooltip\"><div class=\"close-x-light-button\"></div><p class=\"label\"></p><p class=\"tooltip-body\"></p></div>\n            <div class=\"detail-highlight\"></div>\n            <div class=\"main-dark-button back-button enabled\" data-id=\"back\">Back</div>\n            <div class=\"scrim-background\"></div>\n        </div>\n\n\n\n\n\n\n        <div class=\"main-button continue-button enabled\" data-id=\"continue\">Continue</div>\n\n        <div class=\"splash-container\"></div>\n        <div class=\"conclusion-container\"></div>\n\n    </div>\n\n</script>"; });
